#include <bits/stdc++.h>
using namespace std;
const int ma=55;
int n,g[ma],maxn,sl,ans;
vector<int> v;

void dfs(int pos,int rest,int len,int cnt){
    if(rest==0){
        if(--cnt==0){
            ans=len;
            return;
        }
        for(int i=0;i<v.size();i++){
            if(g[v[i]]==0) continue;
            g[v[i]]--;
            dfs(i,len-v[i],len,cnt);
            if(ans!=-1) return;
            g[v[i]]++;
            break;
        }
        return;
    }
    for(int i=pos;i<v.size();i++){
        int l=v[i];
        if(g[l]==0||l>rest) continue;
        g[l]--;
        dfs(i,rest-l,len,cnt);
        if(ans!=-1) return;
        g[l]++;
        if(rest==len||rest==l) break;
        while(i+1<v.size()&&v[i+1]==l) i++;
    }
}

int main(){
    ios::sync_with_stdio(0),cin.tie(0);
    cin>>n;
    for(int i=1,x;i<=n;i++){
        cin>>x;
        g[x]++;
        sl+=x;
        maxn=max(maxn,x);
    }
    for(int i=50;i>=1;i--) if(g[i]) v.push_back(i);
    ans=-1;
    for(int len=maxn;len<=sl;len++){
        if(sl%len) continue;
        dfs(0,len,len,sl/len);
        if(ans!=-1) break;
    }
    cout<<(ans==-1?sl:ans);
    return 0;
}
